const container=document.getElementById("particles"),iconFamilies=["futbol","basketball","volleyball","music","headphones","person-dancing","book","guitar","microphone","leaf","palette","paintbrush","brain","person-running"];function createParticle(){if(!container)return;const e=document.createElement("div"),t=iconFamilies[Math.floor(Math.random()*iconFamilies.length)],a=Math.random()*container.offsetWidth,n=120*Math.random()-60,o=11+10*Math.random(),i=18+28*Math.random(),r=16+24*Math.random();e.className="particle",e.innerHTML=`<i class="fa-solid fa-${t}"></i>`,e.style.left=`${a}px`,e.style.bottom=-40-40*Math.random()+"px",e.style.fontSize=`${i}px`,e.style.opacity=""+(.08+.14*Math.random()),container.appendChild(e),gsap.timeline({defaults:{ease:"none"},onComplete:()=>e.remove()}).to(e,{y:-container.offsetHeight-180,duration:o},0).to(e,{x:n,duration:o},0).to(e,{keyframes:[{x:`+=${r}`,duration:.28*o,ease:"sine.inOut"},{x:"-="+1.8*r,duration:.32*o,ease:"sine.inOut"},{x:"+="+1.35*r,duration:.4*o,ease:"sine.inOut"}]},0).to(e,{rotation:110*Math.random()-55,scale:.72+.48*Math.random(),opacity:0,duration:o},0)}document.addEventListener("DOMContentLoaded",(()=>{for(let e=0;e<10;e+=1)setTimeout(createParticle,240*e);setInterval(createParticle,1400)}));